const previous = $('Extract Report Fields').item.json;
const raw = $input.item.json.text || $input.item.json.output || '';

function extractJson(str) {
  const fenced = str.match(/```(?:json)?\s*([\s\S]*?)```/i);
  const candidate = fenced ? fenced[1] : str;
  const start = candidate.indexOf('{');
  const end = candidate.lastIndexOf('}');
  if (start === -1 || end === -1) return null;
  try {
    return JSON.parse(candidate.slice(start, end + 1));
  } catch (e) {
    return null;
  }
}

const parsed = extractJson(raw) || {};
const validSeverities = ['Mild', 'Moderate', 'Serious', 'Life-threatening'];
const severity = validSeverities.includes(parsed.severity) ? parsed.severity : 'Unclassified';
const parseFailed = Object.keys(parsed).length === 0;

const result = {
  reportId: `ADR-${previous.chatId}-${Date.now()}`,
  timestamp: previous.receivedAt,
  reporterName: previous.reporterName,
  chatId: previous.chatId,
  rawMessage: previous.reportText,
  drugName: parsed.drugName || 'unspecified',
  adverseReaction: parsed.adverseReaction || 'unspecified',
  meddraPreferredTerm: parsed.meddraPreferredTerm || 'unspecified',
  severity,
  isAdverseEventDetected: parsed.isAdverseEventDetected === true,
  confidence: typeof parsed.confidence === 'number' ? parsed.confidence : 0,
  clinicalRationale: parseFailed ? 'AI response could not be parsed automatically; manual review required.' : (parsed.clinicalRationale || 'Not provided'),
  recommendedAction: parseFailed ? 'Manual review required - AI parsing failed' : (parsed.recommendedAction || 'Manual review recommended'),
  requiresUrgentAlert: severity === 'Serious' || severity === 'Life-threatening' || parseFailed
};

return [{ json: result }];

const previous = $('Parse & Validate AI Output').item.json;

function esc(str) {
  return String(str)
    .replace(/\\/g, '\\\\')
    .replace(/\(/g, '\\(')
    .replace(/\)/g, '\\)')
    .replace(/[^\x20-\x7E]/g, '?');
}

function wrap(text, maxChars) {
  const words = String(text || '').split(/\s+/).filter(Boolean);
  const lines = [];
  let current = '';
  for (const word of words) {
    const candidate = current ? current + ' ' + word : word;
    if (candidate.length > maxChars) {
      if (current) lines.push(current);
      current = word;
    } else {
      current = candidate;
    }
  }
  if (current) lines.push(current);
  if (lines.length === 0) lines.push('');
  return lines;
}

const maxChars = 95;

const sections = [
  { size: 16, lines: ['Pharmacovigilance Adverse Event Report'] },
  { size: 10, lines: [''] },
  { size: 11, lines: [`Report ID: ${previous.reportId}`] },
  { size: 11, lines: [`Date/Time: ${previous.timestamp}`] },
  { size: 11, lines: [`Reported By: ${previous.reporterName} (Telegram chat ${previous.chatId})`] },
  { size: 10, lines: [''] },
  { size: 13, lines: ['Suspected Product'] },
  { size: 11, lines: wrap(previous.drugName, maxChars) },
  { size: 10, lines: [''] },
  { size: 13, lines: ['Adverse Reaction'] },
  { size: 11, lines: wrap(previous.adverseReaction, maxChars) },
  { size: 10, lines: [`MedDRA preferred term (AI estimate): ${previous.meddraPreferredTerm}`] },
  { size: 10, lines: [''] },
  { size: 13, lines: ['Severity Classification'] },
  { size: 12, lines: [`${previous.severity}  (confidence: ${previous.confidence})`] },
  { size: 11, lines: wrap(previous.clinicalRationale, maxChars) },
  { size: 10, lines: [''] },
  { size: 13, lines: ['Recommended Action'] },
  { size: 11, lines: wrap(previous.recommendedAction, maxChars) },
  { size: 10, lines: [''] },
  { size: 13, lines: ['Original Report Text'] },
  { size: 10, lines: wrap(previous.rawMessage, maxChars) },
  { size: 10, lines: [''] },
  { size: 8, lines: wrap('Generated automatically by the AI Pharmacovigilance Agent. This is a preliminary AI-assisted triage output and must be reviewed by qualified drug safety personnel before any regulatory action.', maxChars) }
];

const leading = 14;
const streamParts = ['BT', '50 780 Td', `${leading} TL`];
let currentSize = 0;
for (const section of sections) {
  if (section.size !== currentSize) {
    streamParts.push(`/F1 ${section.size} Tf`);
    currentSize = section.size;
  }
  for (const line of section.lines) {
    streamParts.push(`(${esc(line)}) Tj`);
    streamParts.push('T*');
  }
}
streamParts.push('ET');
const contentStream = streamParts.join('\n');

const objects = [];
objects.push('<< /Type /Catalog /Pages 2 0 R >>');
objects.push('<< /Type /Pages /Kids [3 0 R] /Count 1 >>');
objects.push('<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>');
objects.push(`<< /Length ${Buffer.byteLength(contentStream, 'latin1')} >>\nstream\n${contentStream}\nendstream`);
objects.push('<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>');

let pdf = '%PDF-1.4\n';
const offsets = [];
objects.forEach((obj, i) => {
  offsets.push(Buffer.byteLength(pdf, 'latin1'));
  pdf += `${i + 1} 0 obj\n${obj}\nendobj\n`;
});

const xrefOffset = Buffer.byteLength(pdf, 'latin1');
pdf += `xref\n0 ${objects.length + 1}\n0000000000 65535 f \n`;
offsets.forEach((offset) => {
  pdf += `${String(offset).padStart(10, '0')} 00000 n \n`;
});
pdf += `trailer\n<< /Size ${objects.length + 1} /Root 1 0 R >>\nstartxref\n${xrefOffset}\n%%EOF`;

const pdfBase64 = Buffer.from(pdf, 'latin1').toString('base64');

return [{
  json: {
    ...previous,
    pdfBase64,
    pdfFileName: `ADR_Report_${previous.reportId}.pdf`
  }
}];

